#include <bits/stdc++.h>
using namespace std;
const int N=1e5;
int main(){
    int n,w,ans=0,a[100005],s[100005];
    cin>>n>>w;
    if(w==0){
        cout<<0;
        return 0;
    }
    for(int i=1;i<=n;i++){
        int x,b;
        cin>>x>>b;
        a[x]+=b;
    }
    for(int i=1;i<=N;i++)
        s[i]=a[i]+s[i-1];
    for(int i=1;i<=N-w+1;i++)
        ans=max(ans,s[i+w-1]-s[i-1]);
    cout<<ans;
    return 0;
}
